const disponibilidad = $items("Encuesta").map(item => item.json);
const camareros = $items("BD_Camareros").map(item => item.json);
const eventos = $items("Eventos").map(item => item.json);

function clean(value) {
  return String(value ?? "").trim();
}

function upper(value) {
  return clean(value).toUpperCase();
}

function toNumber(value) {
  const n = Number(String(value ?? "").replace(",", "."));
  return Number.isNaN(n) ? 0 : n;
}

function normalizeDate(value) {
  const v = clean(value);

  if (/^\d{2}\/\d{2}\/\d{4}$/.test(v)) return v;

  if (/^\d{4}-\d{2}-\d{2}$/.test(v)) {
    const [y, m, d] = v.split("-");
    return `${d}/${m}/${y}`;
  }

  return v;
}

function normalizeText(value) {
  return clean(value)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase();
}

// 1. Índice de BD de camareros por teléfono
const camarerosPorTelefono = {};

for (const c of camareros) {
  const telefono = clean(c.telefono);
  if (!telefono) continue;

  camarerosPorTelefono[telefono] = {
    telefono,
    nombre: clean(c.nombre),
    fecha_alta: clean(c.fecha_alta),
    horas_trabajadas: toNumber(c.horas_trabajadas),
    nota: toNumber(c.nota),
    fecha_ultimo_evento: clean(c.fecha_ultimo_evento),
    activo: upper(c.activo),
    verificado: upper(c.verificado),
  };
}

// 2. Filtrar eventos NEW reales
const eventosNew = eventos
  .filter(e => clean(e.event_id) !== "")
  .filter(e => upper(e.estado) === "NEW");

// 3. Agrupar eventos por fecha
const eventosPorFecha = {};

for (const e of eventosNew) {
  const fecha = normalizeDate(e.fecha);
  if (!fecha) continue;

  if (!eventosPorFecha[fecha]) {
    eventosPorFecha[fecha] = [];
  }

  eventosPorFecha[fecha].push({
    event_id: clean(e.event_id),
    fecha,
    hora_inicio: clean(e.hora_inicio),
    hora_fin: clean(e.hora_fin),
    tipo: clean(e.tipo),
    nombre_evento: clean(e.nombre_evento),
    ubicacion: clean(e.ubicacion),
    asistentes: toNumber(e.asistentes),
    camareros_necesarios: toNumber(e.camareros_necesarios),
    estado: clean(e.estado),
    prioridad: toNumber(e.prioridad),
    observaciones: clean(e.observaciones),
  });
}

// 4. Procesar disponibilidad por fecha
const salida = [];

for (const [fecha, listaEventos] of Object.entries(eventosPorFecha)) {
  const respuestasDia = disponibilidad.filter(
    d =>
      normalizeDate(d.fecha_evento) === fecha &&
      upper(d.disponible) === "SI"
  );

  const camarerosValidos = [];
  const incidencias = [];
  const telefonosYaIncluidos = new Set();

  for (const d of respuestasDia) {
    const telefono = clean(d.telefono);
    const nombreEncuesta = clean(d.nombre);
    const tieneCoche = upper(d.tiene_coche) === "SI";
    const observaciones = clean(d.observaciones);

    if (!telefono) {
      incidencias.push({
        telefono: "",
        nombre_encuesta: nombreEncuesta,
        fecha,
        motivo: "TELEFONO_VACIO",
      });
      continue;
    }

    const ficha = camarerosPorTelefono[telefono];

    if (!ficha) {
      incidencias.push({
        telefono,
        nombre_encuesta: nombreEncuesta,
        fecha,
        motivo: "NO_ENCONTRADO_EN_BD",
      });
      continue;
    }

    if (ficha.activo !== "SI") {
      incidencias.push({
        telefono,
        nombre_encuesta: nombreEncuesta,
        nombre_bd: ficha.nombre,
        fecha,
        motivo: "NO_ACTIVO",
      });
      continue;
    }

    if (ficha.verificado !== "SI") {
      incidencias.push({
        telefono,
        nombre_encuesta: nombreEncuesta,
        nombre_bd: ficha.nombre,
        fecha,
        motivo: "NO_VERIFICADO",
      });
      continue;
    }

    if (
      nombreEncuesta &&
      ficha.nombre &&
      normalizeText(nombreEncuesta) !== normalizeText(ficha.nombre)
    ) {
      incidencias.push({
        telefono,
        nombre_encuesta: nombreEncuesta,
        nombre_bd: ficha.nombre,
        fecha,
        motivo: "NOMBRE_DISTINTO",
      });
    }

    if (telefonosYaIncluidos.has(telefono)) {
      continue;
    }

    telefonosYaIncluidos.add(telefono);

    camarerosValidos.push({
      telefono,
      nombre: ficha.nombre,
      tiene_coche: tieneCoche,
      observaciones: observaciones,
      fecha_alta: ficha.fecha_alta,
      horas_trabajadas: ficha.horas_trabajadas,
      nota: ficha.nota,
      fecha_ultimo_evento: ficha.fecha_ultimo_evento,
      activo: ficha.activo,
      verificado: ficha.verificado,
    });
  }

  // Orden opcional útil para el siguiente paso:
  // mejor nota primero, y en empate menos horas trabajadas
  camarerosValidos.sort((a, b) => {
    if (b.nota !== a.nota) return b.nota - a.nota;
    return a.horas_trabajadas - b.horas_trabajadas;
  });

  listaEventos.sort((a, b) => a.prioridad - b.prioridad);

  salida.push({
    json: {
      fecha,
      eventos: listaEventos,
      total_eventos: listaEventos.length,
      camareros_validos: camarerosValidos,
      total_camareros_validos: camarerosValidos.length,
      incidencias,
      total_incidencias: incidencias.length,
    }
  });
}

return salida;
